class Solution {
    public int numberOfStableArrays(int zero, int one, int limit) {
        final int MOD = (int) (1e9 + 7);
        long[][] dp = new long[2][Math.max(zero, one) + 1];
        dp[0][0] = 1;
        dp[1][0] = 1;
        for (int i = 1; i <= zero; i++) {
            dp[0][i] = (dp[0][i - 1] + (i <= limit ? 0 : dp[1][i - limit - 1])) % MOD;
        }
        for (int i = 1; i <= one; i++) {
            dp[1][i] = (dp[1][i - 1] + (i <= limit ? 0 : dp[0][i - limit - 1])) % MOD;
        }
        return (int) ((dp[0][zero] + dp[1][one] - 1 + MOD) % MOD);
    }
}
efficiency: HIGH
time complexity: O(max(zero, one))
space complexity: O(max(zero, one))
energy implications: LOW
explanation: Utilizes dynamic programming to track the number of stable arrays ending with 0 and 1, ensuring that subarrays longer than the limit contain both 0 and 1.
